import React, { useState } from 'react';
import createPlayerStats from '../modules/playerStats';

const PlayerStats = () => {
    const [playerStats, setPlayerStats] = useState(createPlayerStats());

    const handleUpgrade = (upgradeFunc) => {
        const result = upgradeFunc();
        if (result.success) {
            setPlayerStats({ ...playerStats }); // Trigger re-render with updated stats
            console.log("Upgrade successful!", result.updatedStats);
        } else {
            console.log("Upgrade failed:", result.message);
        }
    };

    return (
        <div className="player-stats">
            <h2>Player Stats</h2>
            <p>Attack: {playerStats.attack}</p>
            <p>Defense: {playerStats.defense}</p>
            <p>HP: {playerStats.hp}</p>
            <p>Stat Points: {playerStats.statPoints}</p>
            <div className="upgrade-buttons">
                <button onClick={() => handleUpgrade(playerStats.upgradeAttack)}>Upgrade Attack</button>
                <button onClick={() => handleUpgrade(playerStats.upgradeDefense)}>Upgrade Defense</button>
                <button onClick={() => handleUpgrade(playerStats.upgradeHp)}>Upgrade HP</button>
                <button onClick={() => handleUpgrade(playerStats.upgradeAttackPotential)}>Upgrade Attack Potential</button>
                <button onClick={() => handleUpgrade(playerStats.upgradeDefensePotential)}>Upgrade Defense Potential</button>
                <button onClick={() => handleUpgrade(playerStats.upgradeHpPotential)}>Upgrade HP Potential</button>
            </div>
            <button onClick={() => setPlayerStats(playerStats.addStatPoints(5))}>Add 5 Stat Points</button>
        </div>
    );
};

export default PlayerStats;
